//! # BCC voxel quantizer — the 3-D-optimal analog of E_8.
//!
//! `holographic_reconstruction.rs` carves a **cubic** voxel grid
//! (`VoxelCoord{x,y,z}: i32`). Cubic ℤ³ is the *worst* 3-D quantizer:
//! G(ℤ³) = 1/12 ≈ 0.08333. The optimal 3-D lattice quantizer is the
//! **body-centred cubic** lattice BCC = A₃* = D₃*, with normalized second
//! moment G(BCC) = 19/(192·2^(2/3)) ≈ 0.078543 — about **5.7% lower**
//! mean-squared error per sample, and (equivalently) ~28% fewer samples for
//! equal fidelity. BCC is to 3-D what E_8 is to 8-D: the densest-cell,
//! most-isotropic lattice quantizer in its dimension. (E_8 itself is 8-D, so
//! it cannot tile a literal 3-D voxel carve; BCC is the correct analog.)
//!
//! BCC = ℤ³ ∪ (ℤ³ + (½,½,½)): the cubic-grid points PLUS the body centres.
//! Its 8 nearest neighbours sit at the cube-body diagonals (kissing number
//! 8 for the conventional cell; the dual A₃* relevant directions).
//!
//! This module is **additive and opt-in**: it does NOT change the default
//! cubic carve in `holographic_reconstruction.rs`. A caller that wants
//! lower-error reconstruction can quantize sample coordinates onto the BCC
//! lattice via [`nearest_bcc`] before voxelizing.

#![allow(dead_code)]

/// G(ℤ³) = 1/12 — the cubic (default carve) normalized second moment.
pub const G_Z3: f64 = 1.0 / 12.0;
/// G(BCC) ≈ 0.078543 — the optimal 3-D lattice quantizer constant.
pub const G_BCC: f64 = 0.078_543;

/// A BCC lattice point in **half-integer doubled coordinates**: we store
/// `2·(x,y,z)` as integers so both the cubic points (all even) and the
/// body-centre coset (all odd) are representable exactly without floats.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub struct BccCoord {
    pub x2: i64,
    pub y2: i64,
    pub z2: i64,
}

impl BccCoord {
    /// True iff this is a valid BCC point: all-even (a cubic-grid point) or
    /// all-odd (a body centre). Mixed parity is not on the lattice.
    pub fn is_lattice_point(&self) -> bool {
        let pe = self.x2 & 1;
        (self.x2 & 1) == (self.y2 & 1) && (self.y2 & 1) == (self.z2 & 1) && {
            let _ = pe;
            true
        }
    }
}

#[inline]
fn dist3_sq(x: &[f64; 3], p: &[f64; 3]) -> f64 {
    let mut d = 0.0f64;
    for (xv, pv) in x.iter().zip(p.iter()) {
        let e = *xv - *pv;
        d += e * e;
    }
    d
}

/// Nearest BCC lattice point to a real 3-vector `x`.
///
/// BCC = ℤ³ ∪ (ℤ³ + ½). O(1) decode: round to the cubic coset, round the
/// shifted-by-½ coset, return whichever is closer. Output is in doubled
/// integer coordinates ([`BccCoord`]).
pub fn nearest_bcc(x: [f64; 3]) -> BccCoord {
    // Coset 0: ℤ³ (round each coord).
    let c0 = [x[0].round(), x[1].round(), x[2].round()];
    let d0 = dist3_sq(&x, &c0);
    // Coset 1: ℤ³ + ½ (round x−½, add back ½).
    let c1 = [
        (x[0] - 0.5).round() + 0.5,
        (x[1] - 0.5).round() + 0.5,
        (x[2] - 0.5).round() + 0.5,
    ];
    let d1 = dist3_sq(&x, &c1);
    let chosen = if d0 <= d1 { c0 } else { c1 };
    BccCoord {
        x2: (chosen[0] * 2.0).round() as i64,
        y2: (chosen[1] * 2.0).round() as i64,
        z2: (chosen[2] * 2.0).round() as i64,
    }
}

/// Squared quantization error of `x` under the BCC quantizer.
pub fn bcc_error_sq(x: &[f64; 3]) -> f64 {
    let q = nearest_bcc(*x);
    let p = [q.x2 as f64 * 0.5, q.y2 as f64 * 0.5, q.z2 as f64 * 0.5];
    dist3_sq(x, &p)
}

/// Squared quantization error of `x` under the cubic ℤ³ quantizer (round).
pub fn cubic_error_sq(x: &[f64; 3]) -> f64 {
    let mut d = 0.0f64;
    for value in x.iter().take(3) {
        let e = *value - value.round();
        d += e * e;
    }
    d
}

/// Normalized second moment of a 3-D quantizer over uniform samples.
///
/// Both BCC and ℤ³ here are scaled to the **same cell volume**: ℤ³ has unit
/// cell volume; the BCC fundamental cell (ℤ³ ∪ ℤ³+½ with the conventional
/// unit cube) has volume ½ (two points per unit cube). To compare at EQUAL
/// density we normalize by the cell volume V via G = E[‖e‖²]/(3·V^(2/3)).
fn nsm3<F>(samples: &[[f64; 3]], cell_volume: f64, mut err_sq: F) -> f64
where
    F: FnMut(&[f64; 3]) -> f64,
{
    if samples.is_empty() {
        return 0.0;
    }
    let mut acc = 0.0f64;
    for s in samples {
        acc += err_sq(s);
    }
    let mean = acc / samples.len() as f64;
    mean / (3.0 * cell_volume.powf(2.0 / 3.0))
}

/// Empirical normalized second moment of the BCC quantizer (cell volume ½).
pub fn normalized_second_moment_bcc(samples: &[[f64; 3]]) -> f64 {
    nsm3(samples, 0.5, bcc_error_sq)
}

/// Empirical normalized second moment of the cubic ℤ³ quantizer (volume 1).
pub fn normalized_second_moment_cubic(samples: &[[f64; 3]]) -> f64 {
    nsm3(samples, 1.0, cubic_error_sq)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::e8_quantizer::SplitMix64;

    #[test]
    fn nearest_bcc_returns_a_lattice_point() {
        let mut rng = SplitMix64::new(0xBCC0);
        for _ in 0..5000 {
            let v = rng.next_vec8(6.0);
            let x = [v[0], v[1], v[2]];
            let q = nearest_bcc(x);
            assert!(
                q.is_lattice_point(),
                "BCC point must be all-even or all-odd: {q:?}"
            );
        }
    }

    #[test]
    fn bcc_lattice_point_round_trips() {
        // Cubic point (2,0,0)/2 = (1,0,0) and body centre (1,1,1)/2=(.5,.5,.5).
        assert_eq!(
            nearest_bcc([1.0, 0.0, 0.0]),
            BccCoord {
                x2: 2,
                y2: 0,
                z2: 0
            }
        );
        assert_eq!(
            nearest_bcc([0.5, 0.5, 0.5]),
            BccCoord {
                x2: 1,
                y2: 1,
                z2: 1
            }
        );
        assert_eq!(
            nearest_bcc([0.0, 0.0, 0.0]),
            BccCoord {
                x2: 0,
                y2: 0,
                z2: 0
            }
        );
    }

    #[test]
    fn bcc_beats_cubic_on_random_points() {
        let mut rng = SplitMix64::new(0xBCC_BEEF);
        const N: usize = 50_000;
        let mut samples = Vec::with_capacity(N);
        for _ in 0..N {
            let v = rng.next_vec8(8.0);
            samples.push([v[0], v[1], v[2]]);
        }
        let g_bcc = normalized_second_moment_bcc(&samples);
        let g_cubic = normalized_second_moment_cubic(&samples);
        assert!(
            g_bcc < g_cubic,
            "BCC NSM ({g_bcc:.6}) must be below cubic ({g_cubic:.6})"
        );
        // Cubic ≈ 1/12.
        assert!(
            (g_cubic - G_Z3).abs() < 0.003,
            "cubic ≈ 1/12, got {g_cubic:.6}"
        );
        // BCC ≈ 0.0785.
        assert!(
            (g_bcc - G_BCC).abs() < 0.004,
            "BCC ≈ 0.0785, got {g_bcc:.6}"
        );
    }

    #[test]
    fn bench_bcc_vs_cubic_ratio() {
        const N: usize = 200_000;
        let mut rng = SplitMix64::new(0xB0DA_CE17);
        let mut samples = Vec::with_capacity(N);
        for _ in 0..N {
            let v = rng.next_vec8(16.0);
            samples.push([v[0], v[1], v[2]]);
        }
        // COLD.
        let t0 = std::time::Instant::now();
        let g_bcc_cold = normalized_second_moment_bcc(&samples);
        let cold = t0.elapsed();
        let g_cubic_cold = normalized_second_moment_cubic(&samples);
        // WARM.
        let t1 = std::time::Instant::now();
        let g_bcc_warm = normalized_second_moment_bcc(&samples);
        let warm = t1.elapsed();
        let g_cubic_warm = normalized_second_moment_cubic(&samples);
        let ratio = g_bcc_warm / g_cubic_warm;
        let pct = (1.0 - ratio) * 100.0;
        println!(
            "[BCC NSM bench] N={N}\n  COLD: G(BCC)={g_bcc_cold:.6} G(Z3)={g_cubic_cold:.6} \
             decode {cold:?}\n  WARM: G(BCC)={g_bcc_warm:.6} G(Z3)={g_cubic_warm:.6} \
             ratio={ratio:.4} ({pct:.1}% lower error) decode {warm:?}\n  \
             theoretical: G(BCC)={G_BCC:.6} G(Z3)={G_Z3:.6} ratio={:.4}",
            G_BCC / G_Z3
        );
        assert!(ratio < 1.0, "BCC must beat cubic: {ratio}");
        assert!(
            pct > 3.0 && pct < 9.0,
            "expected ~5.7% lower error, got {pct:.1}%"
        );
    }
}
